#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main(){
    int T;
    if(scanf("%d",&T)!=1) return 0;
    int c; while((c=getchar())!='
' && c!=EOF);
    for(int t=0;t<T;++t){
        char line[256];
        if(!fgets(line,sizeof(line),stdin)) break;
        line[strcspn(line,"\n")]='\0';
        char *activity=strtok(line," ");
        char *place=strtok(NULL," ");
        char numLine[256];
        if(!fgets(numLine,sizeof(numLine),stdin)) break;
        int friends,hours;
        sscanf(numLine,"%d %d",&friends,&hours);
        for(char *p=activity;p && *p;++p) *p=toupper(*p);
        for(char *p=place;p && *p;++p) *p=toupper(*p);
        printf("You plan to go %s at the %s.\n",activity,place);
        printf("You will be joined by %d friends and will spend %d hours there.\n",friends,hours);
    }
    return 0;
}

