code.Java:
import java.io.*;
import java.util.*;
public class Main{
    public static void main(String[] args) throws Exception{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        String line=br.readLine();
        if(line==null) return;
        int T=Integer.parseInt(line.trim());
        for(int t=0;t<T;++t){
            String first=br.readLine();
            if(first==null) break;
            String[] parts=first.trim().split("\\s+");
            String activity=parts[0].toUpperCase();
            String place=parts[1].toUpperCase();
            String second=br.readLine();
            if(second==null) break;
            String[] nums=second.trim().split("\\s+");
            int friends=Integer.parseInt(nums[0]);
            int hours=Integer.parseInt(nums[1]);
            System.out.println("You plan to go "+activity+" at the "+place+".");
            System.out.println("You will be joined by "+friends+" friends and will spend "+hours+" hours there.");
        }
    }
}

